/*
EkineraGo büyük demo seed — Aşama 06
Amaç: Türkiye'nin 81 ilinin her biri için 1 örnek üretici/satıcı ve üretici başına 10-30 arası aktif ürün/ilan eklemek.
Önce 001-010, 012 ve Aşama 00-05 dosyaları çalıştırılmış olmalı.
Bu dosya tekrar çalıştırılabilir: @ekinerago81.test üreticilerinin eski ürün/adres/kargo kuralı verilerini yeniler.
*/
USE ekinerago;
SET NAMES utf8mb4;
SET @demo_password_hash := '$2y$12$pxDUzCKrBelOzw1zCfV6X./969R.jmu6sgPPxD1vywmmf.PykMQru';

/* Kategori emniyeti: sadece Sebze / Meyve / Diğer kullanılacak. */
ALTER TABLE categories MODIFY type ENUM('vegetable', 'fruit', 'other') NOT NULL DEFAULT 'other';
ON DUPLICATE KEY UPDATE parent_id = NULL, name = VALUES(name), slug = VALUES(slug), type = VALUES(type), is_active = TRUE;

DROP TEMPORARY TABLE IF EXISTS tmp_stage06_producers;
CREATE TEMPORARY TABLE tmp_stage06_producers (
  plate_code INT UNSIGNED NOT NULL PRIMARY KEY,
  province_name VARCHAR(80) NOT NULL,
  district_name VARCHAR(100) NOT NULL,
  neighborhood_name VARCHAR(120) NOT NULL,
  full_name VARCHAR(120) NOT NULL,
  store_name VARCHAR(160) NOT NULL,
  slug VARCHAR(180) NOT NULL,
  email VARCHAR(160) NOT NULL,
  phone VARCHAR(30) NOT NULL,
  address_text TEXT NOT NULL,
  latitude DECIMAL(10,7) NOT NULL,
  longitude DECIMAL(10,7) NOT NULL,
  verification_status ENUM('pending','verified','rejected') NOT NULL,
  wallet_balance DECIMAL(12,2) NOT NULL,
  shipping_price DECIMAL(12,2) NOT NULL,
  min_order_amount DECIMAL(12,2) NOT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


/* Tekrar çalıştırma temizliği: kullanıcıları silmeden, bu 81 üreticiye ait yenilenebilir verileri temizler. */
DELETE pim FROM product_inventory_movements pim JOIN products p ON p.id = pim.product_id JOIN users u ON u.id = p.producer_id WHERE u.email LIKE '%@ekinerago81.test';
DELETE pi FROM product_images pi JOIN products p ON p.id = pi.product_id JOIN users u ON u.id = p.producer_id WHERE u.email LIKE '%@ekinerago81.test';
DELETE cp FROM campaign_products cp JOIN products p ON p.id = cp.product_id JOIN users u ON u.id = p.producer_id WHERE u.email LIKE '%@ekinerago81.test';
DELETE psr FROM producer_shipping_regions psr JOIN users u ON u.id = psr.producer_id WHERE u.email LIKE '%@ekinerago81.test';
DELETE pbsr FROM producer_bulk_shipping_rules pbsr JOIN users u ON u.id = pbsr.producer_id WHERE u.email LIKE '%@ekinerago81.test';
DELETE a FROM addresses a JOIN users u ON u.id = a.user_id WHERE u.email LIKE '%@ekinerago81.test';
DELETE p FROM products p JOIN users u ON u.id = p.producer_id WHERE u.email LIKE '%@ekinerago81.test';

/* 81 il için üretici mahallesi oluştur. */
SELECT d.id, t.neighborhood_name
FROM tmp_stage06_producers t
JOIN provinces p ON p.plate_code = t.plate_code
JOIN districts d ON d.province_id = p.id AND d.name = t.district_name
ON DUPLICATE KEY UPDATE name = VALUES(name);

/* 81 üretici kullanıcısı. */
SELECT 'producer', t.full_name, t.email, @demo_password_hash, t.phone, t.phone,
       CONCAT('/assets/img/demo/producers/logos/', t.slug, '.png'),
       p.id, d.id, n.id, t.address_text, t.latitude, t.longitude, 'active', NOW(), DATE_SUB(NOW(), INTERVAL (t.plate_code % 20 + 1) DAY)
FROM tmp_stage06_producers t
JOIN provinces p ON p.plate_code = t.plate_code
JOIN districts d ON d.province_id = p.id AND d.name = t.district_name
JOIN neighborhoods n ON n.district_id = d.id AND n.name = t.neighborhood_name
ON DUPLICATE KEY UPDATE full_name=VALUES(full_name), phone=VALUES(phone), whatsapp_phone=VALUES(whatsapp_phone), profile_photo=VALUES(profile_photo), province_id=VALUES(province_id), district_id=VALUES(district_id), neighborhood_id=VALUES(neighborhood_id), address_text=VALUES(address_text), latitude=VALUES(latitude), longitude=VALUES(longitude), status='active';

SELECT u.id, 'Üretici Adresi', t.full_name, t.phone, p.id, d.id, n.id, t.address_text, t.latitude, t.longitude, TRUE
FROM tmp_stage06_producers t
JOIN users u ON u.email = t.email
JOIN provinces p ON p.plate_code = t.plate_code
JOIN districts d ON d.province_id = p.id AND d.name = t.district_name
JOIN neighborhoods n ON n.district_id = d.id AND n.name = t.neighborhood_name;

SELECT u.id, t.store_name, t.slug,
       CONCAT(t.store_name, ', ', t.province_name, ' / ', t.district_name, ' bölgesinde sebze, meyve ve diğer yerel gıda ürünleri için hazırlanmış 81 il demo üretici profilidir. Günlük hasat, doğrudan üreticiden satış, stok takibi ve yerel teslimat senaryoları için dolu veri sağlar.'),
       CONCAT('/assets/img/demo/producers/logos/', t.slug, '.png'),
       CONCAT('/assets/img/demo/producers/covers/', t.slug, '.jpg'),
       t.email, t.phone, t.phone, t.verification_status, 0.00, 0, 0, 0.00,
       CONCAT(t.province_name, ' içi yerel teslimat; uygun ürünlerde Türkiye geneli korumalı kargo. Sipariş sonrası üretici teslimat saatini teyit eder.')
FROM tmp_stage06_producers t JOIN users u ON u.email = t.email
ON DUPLICATE KEY UPDATE store_name=VALUES(store_name), slug=VALUES(slug), description=VALUES(description), logo_path=VALUES(logo_path), cover_photo_path=VALUES(cover_photo_path), contact_email=VALUES(contact_email), contact_phone=VALUES(contact_phone), contact_whatsapp=VALUES(contact_whatsapp), verification_status=VALUES(verification_status), shipping_note=VALUES(shipping_note);

SELECT u.id, t.wallet_balance FROM tmp_stage06_producers t JOIN users u ON u.email = t.email
ON DUPLICATE KEY UPDATE balance = VALUES(balance);

SELECT u.id, p.id, d.id, t.shipping_price, t.min_order_amount, TRUE
FROM tmp_stage06_producers t JOIN users u ON u.email = t.email JOIN provinces p ON p.plate_code = t.plate_code JOIN districts d ON d.province_id = p.id AND d.name = t.district_name;

SELECT u.id, 25.00, 'kg', TRUE, t.shipping_price + 35.00,
       CONCAT(t.province_name, ' çıkışlı karma koli ve toplu siparişlerde Türkiye geneli korumalı gönderim.'), TRUE
FROM tmp_stage06_producers t JOIN users u ON u.email = t.email;

DROP TEMPORARY TABLE IF EXISTS tmp_stage06_products;
CREATE TEMPORARY TABLE tmp_stage06_products (
  producer_email VARCHAR(160) NOT NULL,
  category_id INT UNSIGNED NOT NULL,
  title VARCHAR(160) NOT NULL,
  slug VARCHAR(180) NOT NULL,
  description TEXT NOT NULL,
  unit_type ENUM('kg','piece','bunch','box') NOT NULL,
  price DECIMAL(12,2) NOT NULL,
  stock_quantity DECIMAL(12,3) NOT NULL,
  harvest_offset INT NOT NULL,
  is_preorder_enabled BOOLEAN NOT NULL,
  preorder_deadline_offset INT NULL,
  min_preorder_quantity DECIMAL(10,2) NULL,
  min_preorder_unit ENUM('kg','g','piece') NOT NULL DEFAULT 'kg',
  status ENUM('draft','active','sold_out','paused','deleted') NOT NULL,
  view_count INT UNSIGNED NOT NULL,
  favorite_count INT UNSIGNED NOT NULL,
  created_offset INT NOT NULL,
  INDEX idx_tmp_stage06_products_email (producer_email),
  INDEX idx_tmp_stage06_products_slug (slug)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;






SELECT u.id, tp.category_id, tp.title, tp.slug, tp.description, tp.unit_type, tp.price, tp.stock_quantity,
       DATE_ADD(CURDATE(), INTERVAL tp.harvest_offset DAY),
       tp.is_preorder_enabled,
       CASE WHEN tp.is_preorder_enabled THEN DATE_ADD(CURDATE(), INTERVAL tp.preorder_deadline_offset DAY) ELSE NULL END,
       tp.min_preorder_quantity, tp.min_preorder_unit, tp.status, 0.00, 0, tp.view_count, tp.favorite_count,
       DATE_SUB(NOW(), INTERVAL tp.created_offset DAY)
FROM tmp_stage06_products tp JOIN users u ON u.email = tp.producer_email
ON DUPLICATE KEY UPDATE category_id=VALUES(category_id), title=VALUES(title), description=VALUES(description), unit_type=VALUES(unit_type), price=VALUES(price), stock_quantity=VALUES(stock_quantity), harvest_date=VALUES(harvest_date), is_preorder_enabled=VALUES(is_preorder_enabled), preorder_deadline=VALUES(preorder_deadline), min_preorder_quantity=VALUES(min_preorder_quantity), min_preorder_unit=VALUES(min_preorder_unit), status=VALUES(status), view_count=VALUES(view_count), favorite_count=VALUES(favorite_count), deleted_at=NULL;

SELECT p.id, CONCAT('/assets/img/demo/products/81-il/', t.slug, '-1.jpg'), 0, TRUE
FROM tmp_stage06_products t JOIN users u ON u.email = t.producer_email JOIN products p ON p.producer_id = u.id AND p.slug = t.slug
UNION ALL
SELECT p.id, CONCAT('/assets/img/demo/products/81-il/', t.slug, '-2.jpg'), 1, FALSE
FROM tmp_stage06_products t JOIN users u ON u.email = t.producer_email JOIN products p ON p.producer_id = u.id AND p.slug = t.slug;

SELECT p.id, 'initial', t.stock_quantity, NULL, 'Aşama 06 - 81 il üretici seed başlangıç stoku'
FROM tmp_stage06_products t JOIN users u ON u.email = t.producer_email JOIN products p ON p.producer_id = u.id AND p.slug = t.slug;

/* Kontrol çıktısı */
SELECT COUNT(*) AS stage06_producer_count FROM users WHERE email LIKE '%@ekinerago81.test';
SELECT COUNT(*) AS stage06_product_count FROM products p JOIN users u ON u.id = p.producer_id WHERE u.email LIKE '%@ekinerago81.test';
SELECT p.name AS province, COUNT(DISTINCT u.id) AS producer_count, COUNT(pr.id) AS product_count
FROM provinces p
LEFT JOIN users u ON u.province_id = p.id AND u.email LIKE '%@ekinerago81.test'
LEFT JOIN products pr ON pr.producer_id = u.id
GROUP BY p.id, p.name
ORDER BY p.plate_code;

DROP TEMPORARY TABLE IF EXISTS tmp_stage06_products;
DROP TEMPORARY TABLE IF EXISTS tmp_stage06_producers;